import{_ as a,o as d,c as r,a4 as e}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"硅酸盐 · 孤立四面体 / 环状","description":"","frontmatter":{"title":"硅酸盐 · 孤立四面体 / 环状","mineralGroup":"silicates-isolated"},"headers":[],"relativePath":"zh/mineral-groups/silicates-isolated.md","filePath":"zh/mineral-groups/silicates-isolated.md","lastUpdated":1784176423000}'),i={name:"zh/mineral-groups/silicates-isolated.md"};function l(o,t,s,n,h,c){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="硅酸盐-·-孤立四面体-环状" tabindex="-1">硅酸盐 · 孤立四面体 / 环状 <a class="header-anchor" href="#硅酸盐-·-孤立四面体-环状" aria-label="Permalink to &quot;硅酸盐 · 孤立四面体 / 环状&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>孤立四面体结构（橄榄石型 + 石榴石型 + 锆石型）涵盖多数高折射率 宝石：</p><ul><li><strong>石榴石族</strong>：铁铝榴石、镁铝榴石、锰铝榴石、钙铝榴石、钙 铁榴石、翠榴石、变色石榴石</li><li><strong>橄榄石族</strong>：橄榄石（含镁橄榄石与贵橄榄石）</li><li><strong>锆石族</strong>：蓝锆石（含天然 U/Th 衰变放射性衰变） 环状硅酸盐中重要宝石：电气石（碧玺）、堇青石（Iolite）。</li></ul><h2 id="化学式类型" tabindex="-1">化学式类型 <a class="header-anchor" href="#化学式类型" aria-label="Permalink to &quot;化学式类型&quot;">​</a></h2><p>M₃Al₂(SiO₄)₃ / M₃(SiO₄) + Si₃O₉</p><h2 id="结构" tabindex="-1">结构 <a class="header-anchor" href="#结构" aria-label="Permalink to &quot;结构&quot;">​</a></h2><p>孤立硅酸盐中 [SiO₄]⁴⁻ 四面体不与其他四面体共享氧原子，由 阳离子（M²⁺、M³⁺）在结构空隙中桥接。环状硅酸盐中，3 个 或 6 个 [SiO₄] 四面体首尾连接形成 [Si₃O₉]⁶⁻ 或 [Si₆O₁₈]¹²⁻ 环。</p><h2 id="代表性宝石" tabindex="-1">代表性宝石 <a class="header-anchor" href="#代表性宝石" aria-label="Permalink to &quot;代表性宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>化学式</th><th>亚族</th></tr></thead><tbody><tr><td>Almandine / 铁铝榴石</td><td>Fe₃Al₂(SiO₄)₃</td><td>garnet (Al)</td></tr><tr><td>Pyrope / 镁铝榴石</td><td>Mg₃Al₂(SiO₄)₃</td><td>garnet (Al)</td></tr><tr><td>Spessartine / 锰铝榴石</td><td>Mn₃Al₂(SiO₄)₃</td><td>garnet (Al)</td></tr><tr><td>Grossular / 钙铝榴石</td><td>Ca₃Al₂(SiO₄)₃</td><td>garnet (Al)</td></tr><tr><td>Tsavorite / 沙弗莱</td><td>Ca₃Al₂(SiO₄)₃ + V,Cr</td><td>grossular</td></tr><tr><td>Demantoid / 翠榴石</td><td>Ca₃Fe₂(SiO₄)₃ + Cr</td><td>garnet (Fe)</td></tr><tr><td>Peridot / 橄榄石</td><td>(Mg,Fe)₂SiO₄</td><td>olivine</td></tr><tr><td>Zircon / 锆石</td><td>ZrSiO₄</td><td>zircon</td></tr><tr><td>Topaz / 黄玉</td><td>Al₂SiO₄(F,OH)₂</td><td>topaz</td></tr><tr><td>Chrysoberyl / 金绿宝石</td><td>BeAl₂O₄</td><td>chrysoberyl</td></tr><tr><td>Tourmaline (Elbaite) / 碧玺</td><td>Na(Li,Al)₃Al₆(BO₃)₃Si₆O₁₈(OH)₃</td><td>cyclosilicate</td></tr><tr><td>Iolite (Cordierite) / 堇青石</td><td>Mg₂Al₄Si₅O₁₈</td><td>cyclosilicate</td></tr></tbody></table><p><em>详见<a href="./intro.html">矿物组总览</a>。</em></p>',11)])])}const u=a(i,[["render",l]]);export{m as __pageData,u as default};
